REPLACE INTO `pages` (`id`, `category_id`, `title`, `slug`, `content`, `original_file`, `sort_order`, `created_at`) VALUES ('165', '44', 'SSTA', 'ssta-9804', '\n\n<p align=\"center\"><b><font size=\"5\"  >SEMANA SANTA</font></b></p>\n\n<p align=\"left\"><font ><big><font  size=\"2\">&nbsp;&nbsp;&nbsp;&nbsp; \nMoratalla tiene como tradici??n ancestral, adem??s de las procesiones t??picas de \nestas fechas, de tocar el \ntambor, el toque moratallero es exclusivo, no se repite en ning??n otro lugar de la \npen??nsula, esto se puede constatar en las concentraciones que anualmente se celebran, \ncon motivo de las Jornadas Nacionales para la \nExaltaci??n del Tambor y el Bombo en distintos pueblos y ciudades de nuestra geograf??a nacional.</font></big></font><font   size=\"2\">&nbsp;&nbsp;&nbsp;&nbsp; </font>\n</p>\n\n<p align=\"left\"><font   size=\"2\">Los d??as de Jueves Santo, Viernes Santo y \nDomingo de Resurrecci??n, Moratalla se convierte en un estruendo. Cada tamborista, que es \nel nombre que recibe el nazareno que toca el tambor, intentar?? demostrar su \ndestreza, refinamiento y fuerza, as?? como, la limpieza de sonido de \nsu tambor. El estruendo generado se debe a que cada tamborista hace su toque y no va acompasado con ning??n otro, \naunque individualmente el toque es totalmente r??tmico. Hay quien dice que esto fue \nlo que se oir??a cuando Jesucristo fue crucificado.</font></p>\n\n<p align=\"center\">\n<embed   src=\"../../Asociaciones/Tamboristas/2004/Images/Semana_Santa_2004.swf\"></p>\n\n<p align=\"center\">\n<b><font >\n    <a href=\"Images/tambor3.wav\" >\n<font   size=\"2\">Toque de Tambor Moratallero (6 \n    Seg)</font></a></font></b><a target=\"_self\" href=\"Images/tambor3.wav\"><font   size=\"2\"><img src=\"Images/tamborbo.gif\" alt=\"BEBE1.GIF (10639 bytes)\" border=\"0\"  ></font></a></p>\n\n<p align=\"center\">\n&nbsp;</p>\n\n<p align=\"left\"><font ><big>&nbsp;&nbsp;&nbsp; </big></font></p>\n', 'ssta.htm', '0', '2026-05-07 23:42:45');
